import{_ as a,o as s,c as n,a2 as t}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 15 — Insert Commands","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/15-insert-commands.md","filePath":"chapters/15-insert-commands.md"}'),o={name:"chapters/15-insert-commands.md"};function r(d,e,l,i,p,c){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="chapter-15-—-insert-commands" tabindex="-1">Chapter 15 — Insert Commands <a class="header-anchor" href="#chapter-15-—-insert-commands" aria-label="Permalink to &quot;Chapter 15 — Insert Commands&quot;">​</a></h1><blockquote><p><em>&quot;Typing text is only half of editing—the other half is knowing how to enter insert mode efficiently.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>In Chapter 7, you learned that <code>i</code> enters insert mode.</p><p>But <code>i</code> is just one of many ways to enter insert mode.</p><p>Each method places the cursor at a different position, saving you extra keystrokes.</p><hr><h1 id="all-insert-mode-entries" tabindex="-1">All Insert Mode Entries <a class="header-anchor" href="#all-insert-mode-entries" aria-label="Permalink to &quot;All Insert Mode Entries&quot;">​</a></h1><h2 id="basic-entries" tabindex="-1">Basic Entries <a class="header-anchor" href="#basic-entries" aria-label="Permalink to &quot;Basic Entries&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>i</code></td><td>Insert <strong>before</strong> the cursor</td></tr><tr><td><code>a</code></td><td>Append <strong>after</strong> the cursor</td></tr><tr><td><code>I</code></td><td>Insert at <strong>beginning</strong> of line</td></tr><tr><td><code>A</code></td><td>Append at <strong>end</strong> of line</td></tr><tr><td><code>o</code></td><td>Open a <strong>new line below</strong> and insert</td></tr><tr><td><code>O</code></td><td>Open a <strong>new line above</strong> and insert</td></tr></tbody></table><hr><h1 id="visual-examples" tabindex="-1">Visual Examples <a class="header-anchor" href="#visual-examples" aria-label="Permalink to &quot;Visual Examples&quot;">​</a></h1><h2 id="i-—-insert-before-cursor" tabindex="-1"><code>i</code> — Insert Before Cursor <a class="header-anchor" href="#i-—-insert-before-cursor" aria-label="Permalink to &quot;\`i\` — Insert Before Cursor&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>
<span class="line"><span>     ^</span></span>
<span class="line"><span>     cursor</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press i, type &quot;Good &quot;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hello Good World</span></span></code></pre></div><h2 id="a-—-append-after-cursor" tabindex="-1"><code>a</code> — Append After Cursor <a class="header-anchor" href="#a-—-append-after-cursor" aria-label="Permalink to &quot;\`a\` — Append After Cursor&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>
<span class="line"><span>     ^</span></span>
<span class="line"><span>     cursor</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press a, type &quot; Beautiful&quot;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hello Beautiful World</span></span></code></pre></div><h2 id="i-—-insert-at-line-start" tabindex="-1"><code>I</code> — Insert at Line Start <a class="header-anchor" href="#i-—-insert-at-line-start" aria-label="Permalink to &quot;\`I\` — Insert at Line Start&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   Hello World</span></span>
<span class="line"><span>     ^</span></span>
<span class="line"><span>     cursor</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press I, type &quot;Hi &quot;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Hi Hello World</span></span></code></pre></div><p>Actually, <code>I</code> goes to the very first character of the line (ignoring indentation):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   Hello World</span></span>
<span class="line"><span>^</span></span>
<span class="line"><span>cursor jumps here, then enters insert mode</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press I, type &quot;Hi &quot;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hi Hello World</span></span></code></pre></div><h2 id="a-—-append-at-line-end" tabindex="-1"><code>A</code> — Append at Line End <a class="header-anchor" href="#a-—-append-at-line-end" aria-label="Permalink to &quot;\`A\` — Append at Line End&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>
<span class="line"><span>     ^</span></span>
<span class="line"><span>     cursor</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press A, type &quot;!!!&quot;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hello World!!!</span></span>
<span class="line"><span>                    ^</span></span>
<span class="line"><span>                    cursor jumps here</span></span></code></pre></div><h2 id="o-—-open-line-below" tabindex="-1"><code>o</code> — Open Line Below <a class="header-anchor" href="#o-—-open-line-below" aria-label="Permalink to &quot;\`o\` — Open Line Below&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Line 1</span></span>
<span class="line"><span>Line 2</span></span>
<span class="line"><span>     ^</span></span>
<span class="line"><span>     cursor</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press o:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Line 1</span></span>
<span class="line"><span>                 ← new blank line, insert mode active</span></span>
<span class="line"><span>Line 2</span></span></code></pre></div><h2 id="o-—-open-line-above" tabindex="-1"><code>O</code> — Open Line Above <a class="header-anchor" href="#o-—-open-line-above" aria-label="Permalink to &quot;\`O\` — Open Line Above&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Line 1</span></span>
<span class="line"><span>Line 2</span></span>
<span class="line"><span>     ^</span></span>
<span class="line"><span>     cursor</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press O:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Line 1</span></span>
<span class="line"><span>                 ← new blank line, insert mode active</span></span>
<span class="line"><span>Line 2</span></span></code></pre></div><hr><h1 id="delete-and-insert" tabindex="-1">Delete and Insert <a class="header-anchor" href="#delete-and-insert" aria-label="Permalink to &quot;Delete and Insert&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>s</code></td><td>Delete character under cursor, enter insert mode</td></tr><tr><td><code>S</code></td><td>Delete whole line, enter insert mode</td></tr><tr><td><code>C</code></td><td>Delete from cursor to end of line, enter insert mode</td></tr><tr><td><code>c</code></td><td>Change operator (delete motion + insert)</td></tr><tr><td><code>cc</code></td><td>Change whole line (delete line + insert)</td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>
<span class="line"><span>^</span></span>
<span class="line"><span>cursor on &quot;H&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press s, type &quot;J&quot;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Jello World</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>
<span class="line"><span>Press S (whole line deleted, insert mode):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>         ← empty line, insert mode active</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>
<span class="line"><span>     ^</span></span>
<span class="line"><span>     cursor on &quot;W&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press C:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hello     ← &quot; World&quot; deleted, insert mode active</span></span></code></pre></div><hr><h1 id="special-insert-mode-commands" tabindex="-1">Special Insert Mode Commands <a class="header-anchor" href="#special-insert-mode-commands" aria-label="Permalink to &quot;Special Insert Mode Commands&quot;">​</a></h1><p>While in insert mode, some Ctrl+key combinations still work:</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+w</code></td><td>Delete word backward</td></tr><tr><td><code>Ctrl+u</code></td><td>Delete to beginning of line</td></tr><tr><td><code>Ctrl+t</code></td><td>Indent current line right</td></tr><tr><td><code>Ctrl+d</code></td><td>Indent current line left</td></tr><tr><td><code>Ctrl+r</code></td><td>Insert from register</td></tr><tr><td><code>Ctrl+r=</code></td><td>Insert expression result</td></tr><tr><td><code>Ctrl+n</code></td><td>Autocomplete (next)</td></tr><tr><td><code>Ctrl+p</code></td><td>Autocomplete (previous)</td></tr><tr><td><code>Ctrl+x</code></td><td>Start completion menu</td></tr><tr><td><code>Ctrl+e</code></td><td>Insert character below cursor</td></tr><tr><td><code>Ctrl+y</code></td><td>Insert character above cursor</td></tr></tbody></table><h2 id="ctrl-w-—-delete-word-backward" tabindex="-1"><code>Ctrl+w</code> — Delete Word Backward <a class="header-anchor" href="#ctrl-w-—-delete-word-backward" aria-label="Permalink to &quot;\`Ctrl+w\` — Delete Word Backward&quot;">​</a></h2><p>While typing in insert mode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello Wor|                     ← cursor at &quot;|&quot;</span></span>
<span class="line"><span>Press Ctrl+w:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hello |                        ← &quot;Wor&quot; deleted</span></span></code></pre></div><h2 id="ctrl-u-—-delete-to-line-start" tabindex="-1"><code>Ctrl+u</code> — Delete to Line Start <a class="header-anchor" href="#ctrl-u-—-delete-to-line-start" aria-label="Permalink to &quot;\`Ctrl+u\` — Delete to Line Start&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   Hello World|                ← cursor at &quot;|&quot;</span></span>
<span class="line"><span>Press Ctrl+u:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   |                           ← back to indentation</span></span></code></pre></div><h2 id="ctrl-r-—-insert-from-register" tabindex="-1"><code>Ctrl+r</code> — Insert from Register <a class="header-anchor" href="#ctrl-r-—-insert-from-register" aria-label="Permalink to &quot;\`Ctrl+r\` — Insert from Register&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Type Ctrl+r, then &quot; (quote register):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;clipboard content pasted here&quot;</span></span></code></pre></div><h2 id="ctrl-r-—-calculator" tabindex="-1"><code>Ctrl+r=</code> — Calculator <a class="header-anchor" href="#ctrl-r-—-calculator" aria-label="Permalink to &quot;\`Ctrl+r=\` — Calculator&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Type Ctrl+r, then =:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>=                      ← Vim asks for expression</span></span>
<span class="line"><span>Type 2 + 2, press Enter:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4                      ← Result inserted</span></span></code></pre></div><hr><h1 id="insert-mode-completion" tabindex="-1">Insert Mode Completion <a class="header-anchor" href="#insert-mode-completion" aria-label="Permalink to &quot;Insert Mode Completion&quot;">​</a></h1><p>Vim can autocomplete words while you type:</p><table tabindex="0"><thead><tr><th>Command</th><th>Completion Type</th></tr></thead><tbody><tr><td><code>Ctrl+n</code></td><td>General keyword completion</td></tr><tr><td><code>Ctrl+p</code></td><td>General keyword completion</td></tr><tr><td><code>Ctrl+x</code> <code>Ctrl+f</code></td><td>File name completion</td></tr><tr><td><code>Ctrl+x</code> <code>Ctrl+l</code></td><td>Whole line completion</td></tr><tr><td><code>Ctrl+x</code> <code>Ctrl+o</code></td><td>Omni-completion (LSP based)</td></tr></tbody></table><hr><h1 id="insert-mode-shortcuts" tabindex="-1">Insert Mode Shortcuts <a class="header-anchor" href="#insert-mode-shortcuts" aria-label="Permalink to &quot;Insert Mode Shortcuts&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+[</code></td><td>Exit insert mode (like Escape)</td></tr><tr><td><code>Ctrl+c</code></td><td>Exit insert mode</td></tr><tr><td><code>Shift+Insert</code></td><td>Paste from clipboard</td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>i</code></td><td>Insert before cursor</td></tr><tr><td><code>a</code></td><td>Append after cursor</td></tr><tr><td><code>I</code></td><td>Insert at line beginning</td></tr><tr><td><code>A</code></td><td>Append at line end</td></tr><tr><td><code>o</code></td><td>Open line below</td></tr><tr><td><code>O</code></td><td>Open line above</td></tr><tr><td><code>s</code></td><td>Delete character and insert</td></tr><tr><td><code>S</code></td><td>Delete line and insert</td></tr><tr><td><code>C</code></td><td>Delete to end of line and insert</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li>Choose the right insert command to avoid extra cursor movements.</li><li><code>I</code> and <code>A</code> jump to line start/end before inserting.</li><li><code>o</code> and <code>O</code> create new lines without moving to the end first.</li><li><code>Ctrl+w</code> and <code>Ctrl+u</code> delete while in insert mode.</li><li><code>Ctrl+r</code> lets you paste from registers without leaving insert mode.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Practice each insert command on a sample file.</li><li>Type a paragraph, then use <code>Ctrl+w</code> to delete words backward.</li><li>Use <code>Ctrl+r</code> to paste the contents of register <code>&quot;</code> while in insert mode.</li><li>Compare <code>i</code> vs <code>I</code> and <code>a</code> vs <code>A</code> by editing the same line.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./16-delete-commands.html"><strong>Chapter 16 — Delete Commands</strong></a></p><p>Master deleting text efficiently in Vim—from single characters to entire blocks.</p>`,69)])])}const m=a(o,[["render",r]]);export{u as __pageData,m as default};
